select
id, org_code, org_name, account, name, post, duty, secret_post_type, secret_level, work_status, relation_file,
submit_progress, create_time, update_time, create_user, update_user
from tb_secret_personnel


        and id = #{query.id}


        and org_code = #{query.orgCode}


        and org_name = #{query.orgName}


        and account = #{query.account}


        and name = #{query.name}


        and post = #{query.post}


        and duty = #{query.duty}


        and secret_post_type = #{query.secretPostType}


        and secret_level = #{query.secretLevel}


        and work_status = #{query.workStatus}


        and relation_file = #{query.relationFile}


        and submit_progress = #{query.submitProgress}


        and create_time = #{query.createTime}


        and update_time = #{query.updateTime}


        and create_user = #{query.createUser}


        and update_user = #{query.updateUser}



    limit #{offset}, #{pageSize}

select count(1)
from tb_secret_personnel


        and id = #{query.id}


